// Validate + Route — Produktionsmodus
const items = $input.all();
const results = [];

for (const item of items) {
  const f = item.json.fields || {};
  const postTyp = f.field_2 || f.Field_2 || '';
  const status  = f.field_6 || f.Field_6 || '';
  const itemId  = item.json.Ausweis || item.json.id || f.AUSWEIS || f.id;
  const title   = f.Title || f.Titel || '';

  if (status !== 'Entwurf') continue;
  if (!postTyp) continue;

  // Avatar noch nicht aktiv → diese Typen komplett überspringen
  const avatarTypes = ['Reel', 'Übung', 'Story', 'Uebung'];
  if (avatarTypes.includes(postTyp)) continue;
  const branch = 'feed';

  results.push({
    json: {
      _sp_item_id: itemId,
      _post_typ: postTyp,
      _branch: branch,
      sp_fields: f,
    }
  });
}

return results.slice(0, 1);

// Build Claude Payload für Caption-Generierung
const f = $json.sp_fields;
const pt = $json._post_typ;

// Echte Field-Namen aus SharePoint:
//  field_1 = Thema, field_3 = Content_Brief, field_7 = Hashtag_Thema
const thema       = f.field_1 || '';
const contentBrief = f.field_3 || '';
const hashtagThema = f.field_7 || '';

const PROMPT = `Du bist Texter für die Physio Fuchs Praxis in Ratingen-Lintorf.
Erzeuge eine Instagram-Caption für folgenden Post-Brief.

Post-Typ: ${pt}
Thema: ${thema}
Content-Brief: ${contentBrief}
Hashtag-Thema: ${hashtagThema}

Tonalität-Regeln (verbindlich):
- "Sie"-Form, professionell, sympathisch, motivierend
- KEINE Heilversprechen — verboten: "heilt", "garantiert", "kuriert", "schmerzfrei in X Tagen", "beseitigt"
- KEINE Diagnosen
- Maximal 3 Emojis, sparsam, fachlich passend
- Bei Übungen: Hinweis ergänzen "Bei anhaltenden Beschwerden bitte ärztlich abklären lassen"
- Inklusiv ("Patientinnen und Patienten", nicht Gender-Stern)

Antworte AUSSCHLIESSLICH als JSON, ohne Markdown-Wrapping:
{
  "titel": "<Bild-Headline, max 50 Zeichen>",
  "text": "<Bild-Body, 2-3 kurze Sätze, max 200 Zeichen>",
  "cta": "<Bild-CTA, max 50 Zeichen>",
  "caption": "<volle Instagram-Caption, 2-3 Absätze, endet mit Frage>",
  "hashtags": ["#tag1", "#tag2", "..."]
}
Hashtags: 8-15 Stück, mind. 2 lokale (Ratingen / Lintorf).`;

return [{
  json: {
    _passthrough: $json,
    model: 'claude-sonnet-4-6',
    max_tokens: 2048,
    messages: [{ role: 'user', content: PROMPT }]
  }
}];

// Parse Claude-Response, JSON extrahieren
const resp = $json;
const raw = resp.content?.[0]?.text || resp.completion || '';

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch (e) {
  throw new Error('Claude-Response nicht JSON-parsebar: ' + raw.slice(0, 200));
}

const pt = $node['Code: Build Claude Payload'].json._passthrough;

return [{
  json: {
    ...pt,
    titel:    parsed.titel    || '',
    text:     parsed.text     || '',
    cta:      parsed.cta      || '',
    caption:  parsed.caption  || '',
    hashtags: Array.isArray(parsed.hashtags) ? parsed.hashtags : [],
  }
}];

// HWG-Filter: Caption gegen Heilversprechen-Blacklist prüfen
const HWG_PATTERNS = [
  /\bheilt\b/i,
  /\bheilung\b/i,
  /\bkuriert\b/i,
  /\bgarantiert\b/i,
  /\bgewährleistet?\b/i,
  /\bverspricht\b/i,
  /\bversprechen wir\b/i,
  /\b(schmerzfrei|beschwerdefrei) in (\d+|wenigen|kürzester) (tag|tage|tagen|woche|wochen)\b/i,
  /\bwirkt (100 ?%|sicher|garantiert)\b/i,
  /\bbeseitigt (schmerz|beschwerd|leiden)\b/i,
  /\b(stellt|stellen wir) (ihre )?diagnose\b/i,
  /\bbehandelt erfolgreich\b/i,
  /\b(nebenwirkungsfrei|ohne nebenwirkungen)\b/i,
  /\bbesser als (ärzt|operation|medikament)\b/i,
  /\b(ersetzt|statt) (arzt|ärzt|operation|medikament)\b/i,
];

const f = $json;
const fullText = [f.titel, f.text, f.cta, f.caption].filter(Boolean).join(' ');

const matches = HWG_PATTERNS
  .map(re => ({ pattern: re.source, hit: fullText.match(re) }))
  .filter(x => x.hit);

return [{
  json: {
    ...f,
    _hwg_matches: matches.map(m => m.hit[0]),
    _hwg_clean: matches.length === 0,
  }
}];

// === v18.3 Foto-Branch Node 1 ===
// Berechnet Suchparameter für SP-Foto-Lookup.
const hwg = $('Code: HWG-Filter').first().json;
const validate = $('Code: Validate + Route').first().json;

const itemId = String(validate._sp_item_id).padStart(3, '0');

// Jahr aus Veröffentlichungsdatum, sonst aktuelles Jahr
const datumRaw = hwg.sp_fields?.Ver_x00f6_ffentlichungsdatum;
const year = datumRaw ? new Date(datumRaw).getFullYear() : new Date().getFullYear();

// SP-Pfad (verifiziert 2026-06-08): gleiche Site wie Content-Kalender
const SP_FOTOS_SITE = 'https://physiofuchs889.sharepoint.com/sites/PhysioFuchsTW';
const SP_FOTOS_FOLDER_REL = `/sites/PhysioFuchsTW/Freigegebene Dokumente/Socialmedia/Content_Socialmedia/Fotos/${year}`;

// SP REST API URL für Folder-Listing
// HINWEIS: SP-Pfad-Encoding ist tricky bei Leerzeichen. Wir nutzen einfaches Quoting,
// nicht encodeURIComponent — sonst werden Slashes auch encodiert.
const sp_list_url = `${SP_FOTOS_SITE}/_api/web/GetFolderByServerRelativeUrl('${SP_FOTOS_FOLDER_REL}')/Files`;

const filename_prefix = `PF_${year}_${itemId}_`;

return [{
  json: {
    itemId,
    year,
    sp_fotos_site: SP_FOTOS_SITE,
    sp_fotos_folder_rel: SP_FOTOS_FOLDER_REL,
    sp_list_url,
    filename_prefix,
    // Original-Daten durchreichen
    ...hwg,
  }
}];

// === v18.3 Foto-Branch Node 3 ===
// Sucht in SP-Folder-Listing die zur ItemID passende Foto-Datei.
const cfg = $('Code: Foto-Pfad bauen').first().json;
const prefix = cfg.filename_prefix;

// SP-REST gibt Files in d.results zurück (verbose-Format)
const resp = $input.first().json || {};
let files = [];
if (resp.d?.results) files = resp.d.results;
else if (Array.isArray(resp.value)) files = resp.value;
else if (Array.isArray(resp)) files = resp;

// Match per Filename-Prefix
const matches = files
  .filter(f => (f.Name || f.name || '').startsWith(prefix))
  .sort((a, b) => (a.Name || a.name || '').localeCompare(b.Name || b.name || ''));

const REPO_RAW = 'https://raw.githubusercontent.com/twaese/Physio-Fuchs-Social-Media-Automation/main';
const FALLBACK_URL = `${REPO_RAW}/04_Canva-Vorlagen/html-templates/assets/judith-behandlung-01.png`;

if (matches.length > 0) {
  const m = matches[0];
  const name = m.Name || m.name;
  const serverRel = m.ServerRelativeUrl || m.serverRelativeUrl;
  // Vorhersagbare GitHub-URL nach dem Push
  const gh_path = `04_Canva-Vorlagen/html-templates/assets/photos/${name}`;
  const gh_url = `${REPO_RAW}/${gh_path}`;

  return [{
    json: {
      ...cfg,
      photo_found: true,
      photo_name: name,
      photo_sp_server_rel: serverRel,
      photo_gh_path: gh_path,
      final_photo_url: gh_url,
      _match_log: `Foto gefunden: ${name}`,
    }
  }];
}

// Kein Item-Foto → Fallback
return [{
  json: {
    ...cfg,
    photo_found: false,
    photo_name: null,
    final_photo_url: FALLBACK_URL,
    _match_log: `Kein Item-Foto (prefix "${prefix}" in ${files.length} Files) → Fallback`,
  }
}];

// === v18.3 Foto-Branch Node 5 ===
// SP-Foto-Binary für GitHub-PUT vorbereiten.
const binary = $input.first().binary?.data;
if (!binary || !binary.data) {
  throw new Error('Kein Binary von SP-Foto-Download erhalten');
}

const cfg = $('Code: Foto-Match').first().json;

return [{
  json: {
    repo_path: cfg.photo_gh_path,
    filename: cfg.photo_name,
    public_url: cfg.final_photo_url,
    github_body: {
      message: `WF-02 v18.3: Praxis-Foto ${cfg.photo_name} für PF-${cfg.year}-${cfg.itemId}`,
      content: binary.data,
    },
    _passthrough: cfg,
  }
}];

// === v18.3 Foto-Branch Node 7 (Merge nach IF-Branch) ===
// Vereint True- und False-Pfad: nimmt final_photo_url, schiebt Daten weiter.
const inputs = $input.all();
// Eines der beiden Items kommt durch — egal welches Branch.
const data = inputs[0]?.json || {};

// final_photo_url ist in Code: Foto-Match gesetzt, in beiden Branches verfügbar
const matchData = $('Code: Foto-Match').first().json;

return [{
  json: {
    ...matchData,
    // Diagnose: woher kommt das Foto?
    _foto_branch_taken: matchData.photo_found ? 'item-foto' : 'fallback',
  }
}];

// HTML-Templates fetchen + Platzhalter füllen für IG und FB
// v18.3: BACKGROUND_PHOTO-Platzhalter neu (variabel pro Content)
const REPO_RAW = 'https://raw.githubusercontent.com/twaese/Physio-Fuchs-Social-Media-Automation/main';
const IG_TPL = REPO_RAW + '/04_Canva-Vorlagen/html-templates/instagram/PF_Feed_Standard.html';
const FB_TPL = REPO_RAW + '/04_Canva-Vorlagen/html-templates/facebook/PF_Feed_FB_Standard.html';
const ASSETS_BASE = REPO_RAW + '/04_Canva-Vorlagen/html-templates/assets/';
const FALLBACK_PHOTO = REPO_RAW + '/04_Canva-Vorlagen/html-templates/assets/judith-behandlung-01.png';

const f = $json;
const datum = new Date().toLocaleDateString('de-DE', {
  day: '2-digit', month: '2-digit', year: 'numeric'
});

async function fetchTemplate(url) {
  const r = await this.helpers.httpRequest({ method: 'GET', url, returnFullResponse: false });
  return typeof r === 'string' ? r : (r.body || r);
}

function substitute(html, vars) {
  // Asset-Pfade auf absolute GitHub-Raw-URLs umschreiben (NUR für Logo/Ginkgo etc.)
  html = html.replace(/src="\.\.\/assets\//g, `src="${ASSETS_BASE}`);
  // Platzhalter ersetzen
  for (const [k, v] of Object.entries(vars)) {
    html = html.replaceAll('{{' + k + '}}', String(v));
  }
  return html;
}

const vars = {
  TITEL: f.titel || '',
  TEXT:  f.text  || '',
  CTA:   f.cta   || '',
  DATUM: datum,
  // NEU v18.3: Hintergrund-Foto-URL aus Foto-Branch
  BACKGROUND_PHOTO: f.final_photo_url || FALLBACK_PHOTO,
};

const igTplRaw = await fetchTemplate.call(this, IG_TPL);
const fbTplRaw = await fetchTemplate.call(this, FB_TPL);

const igHtml = substitute(igTplRaw, vars);
const fbHtml = substitute(fbTplRaw, vars);

return [{
  json: {
    ...f,
    _datum: datum,
    _bg_photo: vars.BACKGROUND_PHOTO,
    _ig_html: igHtml,
    _fb_html: fbHtml,
  }
}];

// HTML als Binary File für Gotenberg-Multipart verfügbar machen
const html = $json._ig_html;
const buffer = Buffer.from(html, 'utf8');
return [{
  json: $json,
  binary: {
    ig_html_file: await this.helpers.prepareBinaryData(buffer, 'index.html', 'text/html')
  }
}];

// HTML als Binary für FB-Gotenberg
const html = $node['Code: HTML bauen (IG+FB)'].json._fb_html;
const buffer = Buffer.from(html, 'utf8');
return [{
  json: $json,
  binary: {
    fb_html_file: await this.helpers.prepareBinaryData(buffer, 'index.html', 'text/html')
  }
}];

// Gotenberg-Binary für GitHub-PUT vorbereiten (IG)
const binary = $input.first().binary?.data;
if (!binary || !binary.data) {
  throw new Error('Kein Binary von Gotenberg IG erhalten');
}

const itemId = $('Code: Validate + Route').item.json._sp_item_id;
const ts = new Date().toISOString().replace(/[:T.]/g, '-').slice(0, 19);
const filename = `${itemId}_ig_${ts}.png`;
const path = `04_Canva-Vorlagen/generated-posts/${filename}`;

return [{
  json: {
    repo_path: path,
    filename: filename,
    public_url: `https://raw.githubusercontent.com/twaese/Physio-Fuchs-Social-Media-Automation/main/${path}`,
    github_body: {
      message: `WF-02 auto-post ${itemId} IG ${ts}`,
      content: binary.data,
    },
  }
}];

// Gotenberg-Binary für GitHub-PUT vorbereiten (FB)
const binary = $input.first().binary?.data;
if (!binary || !binary.data) {
  throw new Error('Kein Binary von Gotenberg FB erhalten');
}

const itemId = $('Code: Validate + Route').item.json._sp_item_id;
const ts = new Date().toISOString().replace(/[:T.]/g, '-').slice(0, 19);
const filename = `${itemId}_fb_${ts}.png`;
const path = `04_Canva-Vorlagen/generated-posts/${filename}`;

return [{
  json: {
    repo_path: path,
    filename: filename,
    public_url: `https://raw.githubusercontent.com/twaese/Physio-Fuchs-Social-Media-Automation/main/${path}`,
    github_body: {
      message: `WF-02 auto-post ${itemId} FB ${ts}`,
      content: binary.data,
    },
  }
}];

const f = $('Code: HWG-Filter').first().json;
const itemId = $('Code: Validate + Route').first().json._sp_item_id;

// GitHub-Raw-URLs (public, von Meta ladbar) statt SharePoint-internen URLs
// .first() statt .item — Multi-Branch-Merge sonst undefined
let igUrl = '', fbUrl = '';
try { igUrl = $('Code: IG → GitHub Body').first().json.public_url || ''; } catch(e) { console.log('IG-URL-Lookup failed:', e.message); }
try { fbUrl = $('Code: FB → GitHub Body').first().json.public_url || ''; } catch(e) { console.log('FB-URL-Lookup failed:', e.message); }

// v18.3: Foto-Branch-Diagnose mitloggen
let fotoLog = '';
try {
  const fm = $('Code: Foto-Match').first().json;
  fotoLog = fm.photo_found ? `Foto: ${fm.photo_name}` : 'Foto: Fallback';
} catch (e) { fotoLog = 'Foto: ?'; }

const hashtagBlock = (f.hashtags || []).join(' ');
const captionPure = f.caption;   // OHNE Hashtags — WF-03 hängt sie für IG einmalig dran

const now = new Date().toISOString().replace('T', ' ').slice(0, 16);
const logEntry = `\n${now} WF-02 v18.3: Caption+Bild fertig, HWG sauber, ${fotoLog}, GitHub-Push IG${igUrl?'✓':'✗'}/FB${fbUrl?'✓':'✗'}, Status Bereit`;
const existingLog = f.sp_fields.field_13 || '';

return [{
  json: {
    _sp_item_id: itemId,
    payload: {
      field_10: captionPure,
      field_7:  hashtagBlock,
      field_6:  'Bereit',
      field_8:  igUrl,
      Bild_FB_Dateiname: fbUrl,
      field_13: existingLog + logEntry,
    }
  }
}];

